def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.sqrt(cap) * 27 + np.sin(cap) * 15
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3)
            if cap > 8:
                base_priority += 120 * np.cbrt(cap**2) + 50 * np.cos(cap * 2)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 25 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2 + 250 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.2)) * 30 / j
            if int(cap * 4) % 4 == 0:
                base_priority += 55 * np.tan(cap / 10)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3)**2.5
            for k in range(1, 15):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 6 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 3)
                    if k == 11 and usage > 3.7:
                        fluctuation += 30
            if cap % 3.1 < 0.6:
                base_priority += 50 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2)**3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 20 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 2)
                    if m == 15 and usage > 2.8:
                        fluctuation += 25
            if cap % 2.8 < 0.4:
                base_priority += 40 * np.cos(cap * 2.5)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1)**4
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 30 / n
                    if n % 5 == 3:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 3)
                    if n == 14 and usage > 1.9:
                        fluctuation += 20
            if cap % 1.7 < 0.2:
                base_priority += 35 * np.sin(cap * 3)
        elif 0.6 < usage <= 1:
            base_priority += 170 * (1 - usage) ** 1.5
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.4) * 15 / o
                if usage < 0.05 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.cbrt(cap) * 350
            elif cap < 1.1:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4) * 25
        elif 0.2 < usage <= 0.6:
            base_priority += 320 * (1 - usage) ** 2
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 18 / p
                if usage < 0.02 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 400
            elif cap < 1.2:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        else:
            base_priority += 400 * (1 - usage) ** 3
            for q in range(1, 25):
                pwr = usage ** q
                if q % 2 == 0:
                    fluctuation += (np.cos(pwr * np.pi / 7) - 0.2) * 20 / q
                else:
                    fluctuation += (np.sin(pwr * np.pi / 8) - 0.1) * 17 / q
                if usage < 0.01 * q:
                    fluctuation -= 18 * q
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 450
            elif cap < 1.5:
                base_priority += np.log1p(cap * 40) * 60
            else:
                base_priority += (cap % 8) * 40
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 90
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 80
            elif usage < 0.25:
                priority -= 40
            for s in range(1, 8):
                if int(cap * 1500) % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 110
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 45
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1100) % 29 == 0:
            proximity -= 14
        if int(cap * 220) % 11 == 0:
            proximity += 16
        for v in range(1, 11):
            diff = abs(usage - v / 11)
            if diff < 0.015:
                proximity += 25 / v
            elif diff < 0.04:
                proximity += 13 / v
            else:
                proximity -= 6 / v
        for w in range(1, 10):
            mod_chk = int(cap * 1800) % (w + 11)
            if mod_chk == 0:
                proximity += w * 6
            elif mod_chk == 4:
                proximity -= w * 5
        for x in range(1, 6):
            mod_chk = int(usage * 1800) % (x + 8)
            if mod_chk == 0:
                proximity += 12 * x
            elif mod_chk == 4:
                proximity -= 9 * x
        priority += proximity
        if usage < 0.003:
            for y in range(1, 10):
                priority -= y * 12
        elif usage > 0.97:
            for z in range(1, 8):
                priority += z * 14
        if cap > 3.0:
            if cap % 0.9 < 0.05:
                priority += 50
            if (int(cap * 3200) % 29 == 0) and (usage > 0.8):
                priority += 70
            for aa in range(1, 8):
                if (int(cap * 750) % (aa + 12) == 3) and (usage < 0.9):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
